// ValidateUserInput validates user input data
func (s *UserService) ValidateUserInput(user *User) error {
	if user.Name == "" {
		return errors.New("name is required")
	}
	if user.Email == "" {
		return errors.New("email is required")
	}
	if user.Age < 0 {
		return errors.New("age must be positive")
	}
	if user.Age > 150 {
		return errors.New("age must be reasonable")
	}
	return nil
}

// DataProcessor interface for processing data
type DataProcessor interface {
	ProcessData(data []string) ([]string, error)
}
